#include <stdio.h>
int main() {
    int N, Q;
    scanf("%d %d", &N, &Q);
    int A[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &A[i]);
    }
    while (Q--) {
        int L, R;
        scanf("%d %d", &L, &R);
        long long maxSum = -1;
        int bestX = -1;
        for (int X = 0; X < (1 << 31); X++) {
            long long sum = 0;
            for (int i = L - 1; i < R; i++) {
                sum += (A[i] ^ X);
            }
            if (sum > maxSum) {
                maxSum = sum;
                bestX = X;
            }
        }
        printf("%d\n", bestX);
    }
    return 0;
}

