            int bestX = -1;
            for (int X = 0; X < (1 << 31); X++) {
                long sum = 0;
                for (int i = L - 1; i < R; i++) {
                    sum += (A[i] ^ X);
                }
                if (sum > maxSum) {
                    maxSum = sum;
                    bestX = X;
                }
            }
